def _parse_evaluation(self, response_text: str) -> EvaluationResult:
    """Parse Claude's JSON response into EvaluationResult."""

    try:
        # Try to extract JSON from response (Claude sometimes wraps in markdown)
        if "```json" in response_text:
            json_start = response_text.find("```json") + 7
            json_end = response_text.find("```", json_start)
            response_text = response_text[json_start:json_end].strip()
        elif "```" in response_text:
            json_start = response_text.find("```") + 3
            json_end = response_text.find("```", json_start)
            response_text = response_text[json_start:json_end].strip()

        # Clean up the response text - remove control characters and extra whitespace
        # Replace control characters (except newlines/tabs) with spaces
        cleaned_text = ''.join(c if c.isprintable() or c in '\n\r\t' else ' ' for c in response_text)

        # Try to find the first JSON object in the response
        # Look for the first { and matching }
        start_idx = cleaned_text.find('{')
        if start_idx == -1:
            raise ValueError("No JSON object found in response")

        # Find the matching closing brace
        brace_count = 0
        end_idx = start_idx
        for i, char in enumerate(cleaned_text[start_idx:], start=start_idx):
            if char == '{':
                brace_count += 1
            elif char == '}':
                brace_count -= 1
                if brace_count == 0:
                    end_idx = i + 1
                    break

        if brace_count != 0:
            raise ValueError("Unmatched braces in JSON response")

        json_str = cleaned_text[start_idx:end_idx]
        data = json.loads(json_str)
        return EvaluationResult(**data)

    except (json.JSONDecodeError, ValueError) as e:
        # If parsing fails, return conservative ask_user
        return EvaluationResult(
            decision="ask_user",
            category="moderate_risk",
            reasoning=f"Failed to parse AI response: {str(e)}",
            confidence=0.5,
        )
